import { dashDb } from "../server/data/dash.db.ts";
import { DashRepository } from "../server/data/dash.repository.ts";
import { HookService } from "../server/services/hook.service.ts";
import { AttributionService } from "../server/services/attribution.service.ts";

const repository = new DashRepository(dashDb);
const attributionService = new AttributionService();
const hookService = new HookService(repository, attributionService);

export async function handleHook(args: string[]) {
  const tool = args[0]; // e.g., "claude-code" or "git"
  const eventName = args[1];

  if (tool === "git") {
    if (eventName === "post-commit") {
      await hookService.handleGitPostCommit(process.cwd());
    } else if (eventName === "prepare-commit-msg") {
      await hookService.handleGitPrepareCommitMsg(process.cwd(), args.slice(2));
    }
    return;
  }

  const rawInput = await Bun.stdin.text();
  if (!rawInput) return;

  let payload: any;
  try {
    payload = JSON.parse(rawInput);
  } catch (e) {
    console.error("Failed to parse hook JSON input");
    return;
  }

  if (!payload || typeof payload !== "object") {
    console.error("Invalid hook payload: expected object");
    return;
  }

  await hookService.handleHookEvent(tool, payload);
}

import { DashRepository } from "../data/dash.repository.ts";
import { AttributionService } from "./attribution.service.ts";
import { getRepoId } from "../utils/repoId.ts";
import { extractTokenUsageFromTranscriptJsonl } from "../utils/tokenUsageParser.ts";
import { randomUUID } from "node:crypto";
import { join } from "node:path";
import { statSync, existsSync } from "node:fs";

export class HookService {
  constructor(
    private repository: DashRepository,
    private attributionService: AttributionService
  ) {}

  async handleHookEvent(tool: string, payload: any) {
    const { session_id, cwd, hook_event_name } = payload;
    if (!session_id || !cwd) return;

    const repoId = await getRepoId(cwd);

    // Ensure repo exists
    this.repository.upsertRepo(repoId, cwd);

    // Ensure session exists
    this.repository.insertSession({
      id: session_id,
      repo_id: repoId,
      agent: tool,
      model: payload.model,
      started_at: new Date().toISOString(),
      state: "active"
    });

    // Update session info if this is a SessionStart event
    if (hook_event_name === "SessionStart") {
      this.repository.updateSession(session_id, {
        model: payload.model || "unknown",
        agent: tool
      });
    }

    // Record Event
    const nextSeq = this.repository.getNextEventSeq(session_id);

    this.repository.insertEvent({
      id: randomUUID(),
      session_id,
      seq: nextSeq,
      ts: new Date().toISOString(),
      type: hook_event_name,
      payload_json: JSON.stringify(payload),
      token_usage_json: null
    });

    // Handle Shadow Tracking on Stop
    if (hook_event_name === "Stop") {
      await this.handleShadowSnapshot(session_id, repoId, cwd);
      await this.updateSessionTokenUsageFromTranscript(session_id, payload.transcript_path);
    }

    if (hook_event_name === "PostToolUse" && payload.tool_name === "ExitPlanMode") {
      const updates: Record<string, any> = {};

      // Plan content is in tool_response.plan (Claude Code ≥2.x) or tool_input.plan (older)
      const plan = payload.tool_response?.plan ?? payload.tool_input?.plan;
      if (plan) updates.plan_markdown = plan;

      const allowedPrompts = payload.tool_response?.allowedPrompts ?? payload.tool_input?.allowedPrompts;
      if (allowedPrompts) updates.allowed_prompts_json = JSON.stringify(allowedPrompts);

      if (Object.keys(updates).length > 0) {
        this.repository.updateSession(session_id, updates);
      }
    }

    if (hook_event_name === "SessionEnd") {
      this.repository.updateSession(session_id, { state: "ended", ended_at: new Date().toISOString() });
      await this.updateSessionTokenUsageFromTranscript(session_id, payload.transcript_path);
    }
  }

  async updateSessionTokenUsageFromTranscript(sessionId: string, transcriptPath?: string) {
    if (!transcriptPath || !existsSync(transcriptPath)) return;
    try {
      const content = await Bun.file(transcriptPath).text();
      const tokenUsage = extractTokenUsageFromTranscriptJsonl(content);
      if (tokenUsage) {
        this.repository.updateSession(sessionId, { token_usage_json: JSON.stringify(tokenUsage) });
      }
    } catch (e) {
      console.error("Failed to extract token usage from transcript:", e);
    }
  }

  async handleShadowSnapshot(sessionId: string, repoId: string, cwd: string) {
    try {
      const headSha = (await Bun.$`git -C ${cwd} rev-parse HEAD`.text()).trim();
      const statusRaw = await Bun.$`git -C ${cwd} status --porcelain`.text();
      const dirtyLines = statusRaw.split("\n").filter(l => l.trim() !== "");

      const dirtyPaths: Record<string, string> = {};

      for (const line of dirtyLines) {
        const status = line.slice(0, 2);
        const filePath = line.slice(3).trim();

        if (status.includes("M") || status.includes("A") || status.includes("R") || status.includes("C") || status.includes("U") || status.includes("??")) {
          const fullPath = join(cwd, filePath);

          try {
            if (!existsSync(fullPath) || statSync(fullPath).isDirectory()) continue;
            const blobSha = (await Bun.$`git -C ${cwd} hash-object -w ${fullPath}`.text()).trim();
            dirtyPaths[filePath] = blobSha;
          } catch (e) {
            console.error(`Failed to hash object ${filePath}:`, e);
          }
        } else if (status.includes("D")) {
          dirtyPaths[filePath] = "deleted";
        }
      }

      this.repository.upsertShadowRef({
        session_id: sessionId,
        repo_id: repoId,
        head_commit: headSha,
        dirty_paths_json: JSON.stringify(dirtyPaths),
        updated_at: new Date().toISOString()
      });
    } catch (e) {
      console.error("Shadow snapshot failed:", e);
    }
  }

  async handleGitPrepareCommitMsg(cwd: string, gitArgs: string[]) {
    const msgFile = gitArgs[0];
    if (!msgFile) return;

    const repoId = await getRepoId(cwd);
    const activeSessions = this.repository.getShadowRefsByRepo(repoId);

    if (activeSessions.length === 0) return;

    let content = await Bun.file(msgFile).text();

    for (const session of activeSessions) {
      if (!content.includes(`AI-Session: ${session.session_id}`)) {
        content += `\nAI-Session: ${session.session_id}`;
      }
    }

    await Bun.write(msgFile, content);
  }

  async handleGitPostCommit(cwd: string) {
    const repoId = await getRepoId(cwd);
    const activeSessions = this.repository.getShadowRefsByRepo(repoId);

    if (activeSessions.length === 0) return;

    const headSha = (await Bun.$`git -C ${cwd} rev-parse HEAD`.text()).trim();
    const parentSha = (await Bun.$`git -C ${cwd} rev-parse HEAD~1`.text()).trim();
    const checkpointId = randomUUID();

    this.repository.insertCheckpoint({
      id: checkpointId,
      repo_id: repoId,
      commit_sha: headSha,
      strategy: "manual"
    });

    try {
      const logLine = (await Bun.$`git -C ${cwd} log -1 --format="%an|%ae|%s"`.text()).trim();
      const [authorName, authorEmail, message] = logLine.split("|");
      this.repository.insertCommit({
        sha: headSha,
        repo_id: repoId,
        message: message || "",
        author_name: authorName || "",
        author_email: authorEmail || "",
        date: new Date().toISOString()
      });
    } catch (e) {
      console.error("Failed to store commit author:", e);
    }

    for (const session of activeSessions) {
      const dirtyPaths = JSON.parse(session.dirty_paths_json);
      const attribution = await this.attributionService.calculateAttribution(cwd, parentSha, headSha, dirtyPaths);

      this.repository.updateCheckpointAttribution(checkpointId, JSON.stringify(attribution));
      this.repository.linkCheckpointSession(checkpointId, session.session_id);
      this.repository.deleteShadowRef(session.session_id);

      this.repository.updateSession(session.session_id, { state: "idle" });
    }

    console.log(`Reconciled ${activeSessions.length} sessions for commit ${headSha.slice(0, 7)}`);
  }
}

import { existsSync, readFileSync } from "node:fs";

export interface Message {
  type: "user" | "assistant" | "tool_use" | "plan";
  text?: string;
  name?: string;
  input?: any;
  timestamp: number;
}

export function dashEventsToMessages(
  events: any[],
  fs = { existsSync, readFileSync }
): Message[] {
  // Check if we have a Stop event with a transcript_path
  const stopEvent = events.find((e) => e.type === "Stop");
  const transcriptPath = stopEvent?.payload?.transcript_path;

  if (transcriptPath && fs.existsSync(transcriptPath)) {
    try {
      const fileContent = fs.readFileSync(transcriptPath, "utf8");
      const lines = fileContent.split("\n").filter((l) => l.trim() !== "");
      const messages: Message[] = [];

      for (const line of lines) {
        try {
          const p = JSON.parse(line);
          const msg = p.message;
          if (!msg) continue;

          if (msg.role === "user") {
            const text = Array.isArray(msg.content)
              ? msg.content.map((c: any) => c.text || "").join("")
              : msg.content || "";
            if (text) {
              messages.push({ type: "user", text, timestamp: p.timestamp });
            }
          } else if (msg.role === "assistant") {
            if (Array.isArray(msg.content)) {
              for (const block of msg.content) {
                if (block.type === "text") {
                  messages.push({ type: "assistant", text: block.text, timestamp: p.timestamp });
                } else if (block.type === "tool_use") {
                  messages.push({ type: "tool_use", name: block.name, input: block.input, timestamp: p.timestamp });
                }
              }
            }
          }
        } catch (e) {}
      }
      if (messages.length > 0) return messages;
    } catch (e) {
      console.error("Failed to parse transcript from Stop event:", e);
    }
  }

  const messages: Message[] = [];
  for (const event of events) {
    const p = event.payload;
    if (!p) continue;

    const ts = event.ts;

    switch (event.type) {
      case "UserPromptSubmit":
        messages.push({
          type: "user",
          text: p.prompt || p.text || "",
          timestamp: ts,
        });
        break;

      case "PreToolUse":
        messages.push({
          type: "tool_use",
          name: p.tool_name || p.name,
          input: p.tool_input || p.input,
          timestamp: ts,
        });
        break;

      case "PostToolUse":
        if (p.tool_name === "ExitPlanMode") {
          const plan = p.tool_response?.plan || p.tool_input?.plan;
          if (plan) {
            messages.push({
              type: "plan",
              text: plan,
              timestamp: ts,
            });
          }
        }
        break;

      case "Stop":
        if (p.last_assistant_message || p.text) {
          messages.push({
            type: "assistant",
            text: p.last_assistant_message || p.text,
            timestamp: ts,
          });
        }
        break;
    }
  }
  return messages;
}

import type { Database } from "bun:sqlite";

export class DashRepository {
  constructor(private db: Database) {}

  getSessions(limit = 10) {
    return this.db.query(`
      SELECT s.id, s.repo_id, s.agent, COALESCE(s.model, 'unknown') as model, s.started_at, s.ended_at, s.state,
             r.path as workdir, 
             (SELECT COUNT(*) FROM events e WHERE e.session_id = s.id) as event_count
      FROM sessions s
      JOIN repos r ON s.repo_id = r.id
      WHERE (SELECT COUNT(*) FROM events e WHERE e.session_id = s.id) > 0
      ORDER BY s.started_at DESC
      LIMIT ?
    `).all(limit) as any[];
  }

  getSessionEvents(sessionId: string) {
    return this.db.query("SELECT * FROM events WHERE session_id = ? ORDER BY seq ASC").all(sessionId) as any[];
  }

  getSession(id: string) {
    return this.db.query(`
      SELECT s.id, s.repo_id, s.agent, COALESCE(s.model, 'unknown') as model, s.started_at, s.ended_at, s.state,
             s.token_usage_json, s.plan_markdown, s.plan_transcript_text, s.allowed_prompts_json,
             r.path as workdir
      FROM sessions s
      JOIN repos r ON s.repo_id = r.id
      WHERE s.id = ?
    `).get(id) as any;
  }

  getSessionCheckpoints(sessionId: string) {
    return this.db.query(`
      SELECT c.* FROM checkpoints c
      JOIN checkpoint_sessions cs ON c.id = cs.checkpoint_id
      WHERE cs.session_id = ?
      ORDER BY c.created_at DESC
    `).all(sessionId) as any[];
  }

  getStats() {
    return this.db.query(`
      SELECT 
        COUNT(*) as total_sessions,
        (SELECT COUNT(DISTINCT id) FROM repos) as total_projects
      FROM sessions
    `).get() as any;
  }

  getAllAttribution() {
    return this.db.query(`
      SELECT attribution_json FROM checkpoints WHERE attribution_json IS NOT NULL
    `).all() as any[];
  }

  getRepos() {
    return this.db.query("SELECT * FROM repos").all() as any[];
  }

  getRepoSessionCount(repoId: string) {
    return this.db.query("SELECT COUNT(*) as count FROM sessions WHERE repo_id = ?").get(repoId) as any;
  }

  getRepoCheckpoints(repoId: string) {
    return this.db.query("SELECT attribution_json FROM checkpoints WHERE repo_id = ? AND attribution_json IS NOT NULL").all(repoId) as any[];
  }

  getActivityByDay() {
    return this.db.query(`
      SELECT date(started_at) as date, COUNT(*) as sessions, 0 as lines
      FROM sessions
      GROUP BY date(started_at)
      ORDER BY date ASC
    `).all() as any[];
  }

  getSessionCount() {
    return (this.db.query("SELECT COUNT(*) as count FROM sessions WHERE (SELECT COUNT(*) FROM events e WHERE e.session_id = sessions.id) > 0").get() as any)?.count || 0;
  }

  getSessionsAfter(timestamp: number) {
    // timestamp is unix epoch in seconds
    const dateStr = new Date(timestamp * 1000).toISOString();
    return this.db.query(`
      SELECT s.id, s.repo_id, s.agent, COALESCE(s.model, 'unknown') as model, s.started_at, s.ended_at, s.state,
             r.path as workdir
      FROM sessions s
      JOIN repos r ON s.repo_id = r.id
      WHERE s.started_at > ?
      ORDER BY s.started_at ASC
    `).all(dateStr) as any[];
  }

  // --- Write Methods ---

  upsertRepo(id: string, path: string) {
    return this.db.run(
      "INSERT OR IGNORE INTO repos (id, path) VALUES (?, ?)",
      [id, path]
    );
  }

  insertSession(session: { id: string, repo_id: string, agent: string, model?: string, started_at: string, state?: string }) {
    return this.db.run(
      `INSERT OR IGNORE INTO sessions (id, repo_id, agent, model, started_at, state)
       VALUES (?, ?, ?, ?, ?, ?)`,
      [session.id, session.repo_id, session.agent, session.model || "unknown", session.started_at, session.state || "active"]
    );
  }

  updateSession(id: string, updates: Record<string, any>) {
    const keys = Object.keys(updates);
    const setClause = keys.map(k => `${k} = ?`).join(", ");
    return this.db.run(
      `UPDATE sessions SET ${setClause} WHERE id = ?`,
      [...Object.values(updates), id]
    );
  }

  insertEvent(event: { id: string, session_id: string, seq: number, ts: string, type: string, payload_json: string, token_usage_json?: string | null }) {
    return this.db.run(
      `INSERT INTO events (id, session_id, seq, ts, type, payload_json, token_usage_json)
       VALUES (?, ?, ?, ?, ?, ?, ?)`,
      [event.id, event.session_id, event.seq, event.ts, event.type, event.payload_json, event.token_usage_json ?? null]
    );
  }

  getNextEventSeq(sessionId: string): number {
    const res = this.db.query("SELECT COALESCE(MAX(seq), -1) + 1 as next_seq FROM events WHERE session_id = ?").get(sessionId) as { next_seq: number };
    return res.next_seq;
  }

  upsertShadowRef(shadow: { session_id: string, repo_id: string, head_commit: string, dirty_paths_json: string, updated_at: string }) {
    return this.db.run(
      `INSERT OR REPLACE INTO shadow_refs (session_id, repo_id, head_commit, dirty_paths_json, updated_at)
       VALUES (?, ?, ?, ?, ?)`,
      [shadow.session_id, shadow.repo_id, shadow.head_commit, shadow.dirty_paths_json, shadow.updated_at]
    );
  }

  deleteShadowRef(sessionId: string) {
    return this.db.run("DELETE FROM shadow_refs WHERE session_id = ?", [sessionId]);
  }

  getShadowRefsByRepo(repoId: string) {
    return this.db.query("SELECT * FROM shadow_refs WHERE repo_id = ?").all(repoId) as any[];
  }

  insertCheckpoint(checkpoint: { id: string, repo_id: string, commit_sha: string, strategy: string, attribution_json?: string }) {
    return this.db.run(
      "INSERT OR IGNORE INTO checkpoints (id, repo_id, commit_sha, strategy, attribution_json) VALUES (?, ?, ?, ?, ?)",
      [checkpoint.id, checkpoint.repo_id, checkpoint.commit_sha, checkpoint.strategy, checkpoint.attribution_json || null]
    );
  }

  updateCheckpointAttribution(id: string, attributionJson: string) {
    return this.db.run("UPDATE checkpoints SET attribution_json = ? WHERE id = ?", [attributionJson, id]);
  }

  getCheckpointBySha(sha: string) {
    return this.db.query("SELECT * FROM checkpoints WHERE commit_sha = ?").get(sha) as any;
  }

  linkCheckpointSession(checkpointId: string, sessionId: string) {
    return this.db.run(
      "INSERT OR IGNORE INTO checkpoint_sessions (checkpoint_id, session_id) VALUES (?, ?)",
      [checkpointId, sessionId]
    );
  }

  getSessionAuthor(sessionId: string) {
    return this.db.query(`
      SELECT c.author_name, c.author_email
      FROM commits c
      JOIN checkpoints cp ON cp.commit_sha = c.sha
      JOIN checkpoint_sessions cs ON cs.checkpoint_id = cp.id
      WHERE cs.session_id = ?
      ORDER BY c.date DESC LIMIT 1
    `).get(sessionId) as { author_name: string; author_email: string } | null;
  }

  getTokenUsageByDay() {
    return this.db.query(`
      SELECT date(started_at) as date,
        SUM(COALESCE(json_extract(token_usage_json,'$.input_tokens'),0)) as input_tokens,
        SUM(COALESCE(json_extract(token_usage_json,'$.output_tokens'),0)) as output_tokens,
        SUM(COALESCE(json_extract(token_usage_json,'$.cache_creation_tokens'),0)) + SUM(COALESCE(json_extract(token_usage_json,'$.cache_read_tokens'),0)) as cache_tokens
      FROM sessions
      WHERE token_usage_json IS NOT NULL
      GROUP BY date(started_at) ORDER BY date ASC
    `).all() as any[];
  }

  getFileChangesByDay() {
    return this.db.query(`
      SELECT date(s.started_at) as date,
        SUM(COALESCE(json_extract(cp.attribution_json,'$.ai_additions'),0)) as additions,
        SUM(COALESCE(json_extract(cp.attribution_json,'$.ai_deletions'),0)) as deletions
      FROM sessions s
      JOIN checkpoint_sessions cs ON cs.session_id = s.id
      JOIN checkpoints cp ON cp.id = cs.checkpoint_id
      WHERE cp.attribution_json IS NOT NULL
      GROUP BY date(s.started_at) ORDER BY date ASC
    `).all() as any[];
  }

  insertCommit(commit: { sha: string, repo_id: string, message: string, author_name: string, author_email: string, date: string }) {
    return this.db.run(
      `INSERT OR IGNORE INTO commits (sha, repo_id, message, author_name, author_email, date)
       VALUES (?, ?, ?, ?, ?, ?)`,
      [commit.sha, commit.repo_id, commit.message, commit.author_name, commit.author_email, commit.date]
    );
  }
}

import { Database } from "bun:sqlite";

export function runMigrations(db: Database) {
  db.run("PRAGMA foreign_keys = ON;");

  // 1. Repos
  db.run(`
    CREATE TABLE IF NOT EXISTS repos (
      id TEXT PRIMARY KEY,
      path TEXT NOT NULL UNIQUE,
      project_hash TEXT,
      remote_url TEXT,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP
    );
  `);

  // 2. Sessions
  db.run(`
    CREATE TABLE IF NOT EXISTS sessions (
      id TEXT PRIMARY KEY,
      repo_id TEXT NOT NULL,
      agent TEXT NOT NULL,
      model TEXT,
      started_at DATETIME NOT NULL,
      ended_at DATETIME,
      state TEXT NOT NULL DEFAULT 'active',
      FOREIGN KEY (repo_id) REFERENCES repos(id)
    );
  `);

  // 3. Events
  db.run(`
    CREATE TABLE IF NOT EXISTS events (
      id TEXT PRIMARY KEY,
      session_id TEXT NOT NULL,
      seq INTEGER NOT NULL,
      ts DATETIME NOT NULL,
      type TEXT NOT NULL,
      payload_json TEXT NOT NULL,
      FOREIGN KEY (session_id) REFERENCES sessions(id)
    );
  `);

  // 4. Shadow Refs (Incremental capture between stops)
  db.run(`
    CREATE TABLE IF NOT EXISTS shadow_refs (
      session_id TEXT PRIMARY KEY,
      repo_id TEXT NOT NULL,
      head_commit TEXT,
      dirty_paths_json TEXT,
      updated_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      FOREIGN KEY (session_id) REFERENCES sessions(id),
      FOREIGN KEY (repo_id) REFERENCES repos(id)
    );
  `);

  // 5. Checkpoints (Commit consolidation)
  db.run(`
    CREATE TABLE IF NOT EXISTS checkpoints (
      id TEXT PRIMARY KEY,
      repo_id TEXT NOT NULL,
      commit_sha TEXT NOT NULL UNIQUE,
      created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
      strategy TEXT,
      attribution_json TEXT,
      token_usage_json TEXT,
      FOREIGN KEY (repo_id) REFERENCES repos(id)
    );
  `);

  // 6. Checkpoint Sessions (M:N relationship)
  db.run(`
    CREATE TABLE IF NOT EXISTS checkpoint_sessions (
      checkpoint_id TEXT NOT NULL,
      session_id TEXT NOT NULL,
      PRIMARY KEY (checkpoint_id, session_id),
      FOREIGN KEY (checkpoint_id) REFERENCES checkpoints(id),
      FOREIGN KEY (session_id) REFERENCES sessions(id)
    );
  `);

  // 7. Commits Cache
  db.run(`
    CREATE TABLE IF NOT EXISTS commits (
      sha TEXT PRIMARY KEY,
      repo_id TEXT NOT NULL,
      message TEXT,
      author_name TEXT,
      author_email TEXT,
      date DATETIME NOT NULL,
      FOREIGN KEY (repo_id) REFERENCES repos(id)
    );
  `);

  // Add token_usage_json to sessions (idempotent)
  try {
    db.run("ALTER TABLE sessions ADD COLUMN token_usage_json TEXT");
  } catch (_) {
    // Column already exists
  }

  // Add plan_markdown, plan_transcript_text, allowed_prompts_json to sessions (idempotent)
  try {
    db.run("ALTER TABLE sessions ADD COLUMN plan_markdown TEXT");
  } catch (_) {}

  try {
    db.run("ALTER TABLE sessions ADD COLUMN plan_transcript_text TEXT");
  } catch (_) {}

  try {
    db.run("ALTER TABLE sessions ADD COLUMN allowed_prompts_json TEXT");
  } catch (_) {}

  // Add token_usage_json to events (idempotent)
  try {
    db.run("ALTER TABLE events ADD COLUMN token_usage_json TEXT");
  } catch (_) {}

  console.log("Migrations applied successfully.");
}

import { expect, test, describe } from "bun:test";
import { dashEventsToMessages } from "./eventParser.ts";

describe("eventParser", () => {
  test("should fallback to events if transcript does not exist", () => {
    const events = [
      { type: "UserPromptSubmit", ts: 100, payload: { text: "hello" } },
      { type: "Stop", ts: 200, payload: { text: "hi there" } },
    ];

    const fsMock = {
      existsSync: () => false,
      readFileSync: () => "",
    };

    const messages = dashEventsToMessages(events, fsMock as any);
    expect(messages).toHaveLength(2);
    expect(messages[0]).toEqual({ type: "user", text: "hello", timestamp: 100 });
    expect(messages[1]).toEqual({ type: "assistant", text: "hi there", timestamp: 200 });
  });

  test("should parse transcript if it exists", () => {
    const events = [
      { type: "Stop", ts: 200, payload: { transcript_path: "/path/to/transcript" } },
    ];

    const transcript = JSON.stringify({
      timestamp: 150,
      message: { role: "user", content: "from transcript" }
    }) + "\n" + JSON.stringify({
      timestamp: 160,
      message: { role: "assistant", content: [{ type: "text", text: "response" }] }
    });

    const fsMock = {
      existsSync: (p: string) => p === "/path/to/transcript",
      readFileSync: () => transcript,
    };

    const messages = dashEventsToMessages(events, fsMock as any);
    expect(messages).toHaveLength(2);
    expect(messages[0].text).toBe("from transcript");
    expect(messages[1].text).toBe("response");
