                    <div className="timeline-content">
                      <div className="tool-call">
                        <div className="tool-call-header" onClick={() => toggleTool(gm.originalIndex)}>
                          {isExpanded ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
                          <Terminal size={14} />
                          <span>{gm.name}</span>
                        </div>
                        {isExpanded && (
